1	package planner
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"sort"
7		"strings"
8	
9		"entire.io/entire/git-sync/internal/validation"
10		"github.com/go-git/go-git/v6/plumbing"
11	)
12	
13	// RefKind distinguishes branch refs from tag refs.
14	type RefKind string
15	
16	const (
17		RefKindBranch RefKind = "branch"
18		RefKindTag    RefKind = "tag"
19	)
20	
21	// Action represents the planned operation on a ref.
22	type Action string
23	
24	const (
25		ActionCreate Action = "create"
26		ActionUpdate Action = "update"
27		ActionDelete Action = "delete"
28		ActionSkip   Action = "skip"
29		ActionBlock  Action = "block"
30	)
31	
32	// RefMapping is a user-specified source:target mapping.
33	type RefMapping = validation.RefMapping
34	
35	// DesiredRef represents a source ref that should be mirrored to a target ref.
36	type DesiredRef struct {
37		Kind       RefKind
38		Label      string
39		SourceRef  plumbing.ReferenceName
40		TargetRef  plumbing.ReferenceName
41		SourceHash plumbing.Hash
42	}
43	
44	// ManagedTarget tracks which target refs are managed by git-sync.
45	type ManagedTarget struct {
46		Kind  RefKind
47		Label string
48	}
49	
50	// BranchPlan describes the planned action for a single ref.
51	type BranchPlan struct {
52		Branch     string                 `json:"branch"`
53		SourceRef  plumbing.ReferenceName `json:"sourceRef"`
54		TargetRef  plumbing.ReferenceName `json:"targetRef"`
55		SourceHash plumbing.Hash          `json:"sourceHash"`
56		TargetHash plumbing.Hash          `json:"targetHash"`
57		Kind       RefKind                `json:"kind"`
58		Action     Action                 `json:"action"`
59		Reason     string                 `json:"reason"`
60	}
61	
62	func (p BranchPlan) MarshalJSON() ([]byte, error) {
63		type bp struct {
64			Branch     string  `json:"branch"`
65			SourceRef  string  `json:"sourceRef"`
66			TargetRef  string  `json:"targetRef"`
67			SourceHash string  `json:"sourceHash"`
68			TargetHash string  `json:"targetHash"`
69			Kind       RefKind `json:"kind"`
70			Action     Action  `json:"action"`
71			Reason     string  `json:"reason"`
72		}
73		data, err := json.Marshal(bp{
74			Branch:     p.Branch,
75			SourceRef:  p.SourceRef.String(),
76			TargetRef:  p.TargetRef.String(),
77			SourceHash: p.SourceHash.String(),
78			TargetHash: p.TargetHash.String(),
79			Kind:       p.Kind,
80			Action:     p.Action,
81			Reason:     p.Reason,
82		})
83		if err != nil {
84			return nil, fmt.Errorf("marshal branch plan: %w", err)
85		}
86		return data, nil
87	}
88	
89	// ShortHash returns the first 8 characters of a hash, or "<zero>" for zero hashes.
90	func ShortHash(hash plumbing.Hash) string {
91		if hash.IsZero() {
92			return "<zero>"
93		}
94		s := hash.String()
95		if len(s) > 8 {
96			return s[:8]
97		}
98		return s
99	}
100	
101	// RefKindFromName infers the ref kind from a fully qualified ref name.
102	func RefKindFromName(name plumbing.ReferenceName) RefKind {
103		switch {
104		case name.IsBranch():
105			return RefKindBranch
106		case name.IsTag():
107			return RefKindTag
108		default:
109			return ""
110		}
111	}
112	
113	// ActionForTargetHash returns ActionCreate for zero hashes, ActionUpdate otherwise.
114	func ActionForTargetHash(hash plumbing.Hash) Action {
115		if hash.IsZero() {
116			return ActionCreate
117		}
118		return ActionUpdate
119	}
120	
121	// BranchMapFromRefHashMap extracts short branch names from a ref hash map.
122	func BranchMapFromRefHashMap(refs map[plumbing.ReferenceName]plumbing.Hash) map[string]plumbing.Hash {
123		branches := make(map[string]plumbing.Hash)
124		for name, hash := range refs {
125			if name.IsBranch() {
126				branches[name.Short()] = hash
127			}
128		}
129		return branches
130	}
131	
132	// SelectBranches filters branches to only the requested ones.
133	// If requested is empty, returns all.
134	func SelectBranches(source map[string]plumbing.Hash, requested []string) map[string]plumbing.Hash {
135		if len(requested) == 0 {
136			return source
137		}
138		selected := make(map[string]plumbing.Hash, len(requested))
139		for _, branch := range requested {
140			if hash, ok := source[branch]; ok {
141				selected[branch] = hash
142			}
143		}
144		return selected
145	}
146	
147	// RefPrefixes computes the ref-prefix arguments for v2 ls-refs based on
148	// the user's configuration.
149	func RefPrefixes(mappings []RefMapping, includeTags bool) []string {
150		prefixSet := map[string]struct{}{}
151		if len(mappings) > 0 {
152			for _, m := range mappings {
153				src := strings.TrimSpace(m.Source)
154				switch {
155				case strings.HasPrefix(src, "refs/tags/"):
156					prefixSet["refs/tags/"] = struct{}{}
157				case strings.HasPrefix(src, "refs/heads/"):
158					prefixSet["refs/heads/"] = struct{}{}
159				case !strings.HasPrefix(src, "refs/"):
160					prefixSet["refs/heads/"] = struct{}{}
161				}
162			}
163		} else {
164			prefixSet["refs/heads/"] = struct{}{}
165		}
166		if includeTags {
167			prefixSet["refs/tags/"] = struct{}{}
168		}
169		prefixes := make([]string, 0, len(prefixSet))
170		for p := range prefixSet {
171			prefixes = append(prefixes, p)
172		}
173		sort.Strings(prefixes)
174		return prefixes
175	}
176	
177	// CopyRefHashMap returns a shallow copy of a ref hash map.
178	func CopyRefHashMap(input map[plumbing.ReferenceName]plumbing.Hash) map[plumbing.ReferenceName]plumbing.Hash {
179		out := make(map[plumbing.ReferenceName]plumbing.Hash, len(input))
180		for k, v := range input {
181			out[k] = v
182		}
183		return out
184	}
185	
186	// DesiredSubset returns the subset of desired refs that match the given plans.
187	func DesiredSubset(
188		desired map[plumbing.ReferenceName]DesiredRef,
189		plans []BranchPlan,
190	) map[plumbing.ReferenceName]DesiredRef {
191		out := make(map[plumbing.ReferenceName]DesiredRef, len(plans))
192		for _, plan := range plans {
193			if ref, ok := desired[plan.TargetRef]; ok {
194				out[plan.TargetRef] = ref
195			}
196		}
197		return out
198	}
199	
200	// SingleDesired builds a single-entry desired ref map.
201	func SingleDesired(sourceRef, targetRef plumbing.ReferenceName, hash plumbing.Hash) map[plumbing.ReferenceName]DesiredRef {
202		return map[plumbing.ReferenceName]DesiredRef{
203			targetRef: {
204				Kind:       RefKindBranch,
205				Label:      targetRef.Short(),
206				SourceRef:  sourceRef,
207				TargetRef:  targetRef,
208				SourceHash: hash,
209			},
210		}
211	}
212	
213	// SingleHaveMap builds a single-entry have map for fetch negotiation.
214	func SingleHaveMap(hash plumbing.Hash) map[plumbing.ReferenceName]plumbing.Hash {
215		if hash.IsZero() {
216			return nil
217		}
218		return map[plumbing.ReferenceName]plumbing.Hash{
219			plumbing.ReferenceName("refs/gitsync/have"): hash,
220		}
221	}
222	
223	// BootstrapTempRef returns the temporary ref name used during batched bootstrap.
224	func BootstrapTempRef(targetRef plumbing.ReferenceName) plumbing.ReferenceName {
225		return plumbing.ReferenceName("refs/gitsync/bootstrap/heads/" + targetRef.Short())
226	}
227	
228	// FormatPlanLine formats a single plan entry for human-readable output.
229	func FormatPlanLine(plan BranchPlan) string {
230		label := plan.Branch
231		if plan.TargetRef != "" {
232			label = plan.TargetRef.String()
233		}
234		line := fmt.Sprintf("%s %s", strings.ToUpper(string(plan.Action)), label)
235		if plan.Reason != "" {
236			line += " - " + plan.Reason
237		}
238		return line
239	}
