409	// ObjectsToPush computes the set of objects that need to be sent to the target.
410	//
411	// A fetch with target refs as haves prunes the source pack server-side, so
412	// objects reachable from a have are intentionally absent from the local
413	// store. Both top-level wants and transitive references encountered during
414	// the walk may be missing for this reason — they're treated as implicitly
415	// have'd by the target and excluded from the push pack. The target's
416	// receive-pack accepts ref updates referencing such objects because it
417	// already has them under one of its existing refs.
418	func ObjectsToPush(store storer.EncodedObjectStorer, wants []plumbing.Hash, targetRefs map[plumbing.ReferenceName]plumbing.Hash) ([]plumbing.Hash, error) {
419		haveSet := make(map[plumbing.Hash]struct{})
420		for _, h := range targetRefs {
421			if !h.IsZero() {
422				haveSet[h] = struct{}{}
423			}
424		}
425	
426		filteredWants := make([]plumbing.Hash, 0, len(wants))
427		for _, h := range wants {
428			if _, ok := haveSet[h]; !ok {
429				filteredWants = append(filteredWants, h)
430			}
431		}
432		if len(filteredWants) == 0 {
433			return nil, nil
434		}
435	
436		seen := make(map[plumbing.Hash]bool, len(filteredWants)*4)
437		objects := make([]plumbing.Hash, 0, len(filteredWants)*16)
438		for _, h := range filteredWants {
439			if err := collectObjects(store, h, haveSet, seen, &objects); err != nil {
440				return nil, err
441			}
442		}
443		return objects, nil
444	}
445	
446	func collectObjects(
447		store storer.EncodedObjectStorer,
448		hash plumbing.Hash,
449		haves map[plumbing.Hash]struct{},
450		seen map[plumbing.Hash]bool,
451		out *[]plumbing.Hash,
452	) error {
453		if hash.IsZero() {
454			return nil
455		}
456		if _, ok := haves[hash]; ok {
457			return nil
458		}
459		if seen[hash] {
460			return nil
461		}
462		seen[hash] = true
463	
464		obj, err := store.EncodedObject(plumbing.AnyObject, hash)
465		if err != nil {
466			if errors.Is(err, plumbing.ErrObjectNotFound) {
467				// Reachable from a target-ref have via the source server's
468				// pack-prune; the target already has it, so it stays out
469				// of the push.
470				return nil
471			}
472			return fmt.Errorf("load object %s: %w", hash, err)
473		}
474	
475		switch obj.Type() {
476		case plumbing.CommitObject:
477			commit, err := object.GetCommit(store, hash)
478			if err != nil {
479				return fmt.Errorf("load commit %s: %w", hash, err)
480			}
481			if err := collectObjects(store, commit.TreeHash, haves, seen, out); err != nil {
482				return err
483			}
484			for _, ph := range commit.ParentHashes {
485				if err := collectObjects(store, ph, haves, seen, out); err != nil {
486					return err
487				}
488			}
489		case plumbing.TreeObject:
490			tree, err := object.GetTree(store, hash)
491			if err != nil {
492				return fmt.Errorf("load tree %s: %w", hash, err)
493			}
494			for _, entry := range tree.Entries {
495				if err := collectObjects(store, entry.Hash, haves, seen, out); err != nil {
496					return err
497				}
498			}
499		case plumbing.TagObject:
500			tag, err := object.GetTag(store, hash)
501			if err != nil {
502				return fmt.Errorf("load tag %s: %w", hash, err)
503			}
504			if err := collectObjects(store, tag.Target, haves, seen, out); err != nil {
505				return err
506			}
507		case plumbing.BlobObject:
508			// Blobs are leaf objects — nothing to recurse into.
509		case plumbing.InvalidObject, plumbing.OFSDeltaObject, plumbing.REFDeltaObject, plumbing.AnyObject:
510			return fmt.Errorf("unsupported object type %s for %s", obj.Type(), hash)
511		}
512	
513		*out = append(*out, hash)
514		return nil
515	}
