393	// needsLocalSourceClosure reports whether the sync must populate the
394	// in-memory store with the full source closure before running. The fetch
395	// is required when:
396	//   - Force or prune is set: incremental relay is disabled, so the
397	//     materialized fallback will run and needs the closure.
398	//   - Any desired ref already exists on target at a different hash: a
399	//     branch fast-forward check will need ancestry data, or a tag retarget
400	//     will route to materialized.
401	//
402	// When all desired refs are either skips (target hash matches source) or
403	// creates (target hash is zero), incremental relay handles the push without
404	// the closure — the upfront fetch would just be wasted bandwidth, since
405	// relay does its own FetchPack on the source.
406	func needsLocalSourceClosure(
407		cfg Config,
408		desired map[plumbing.ReferenceName]planner.DesiredRef,
409		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
410	) bool {
411		if cfg.Force || cfg.Prune {
412			return true
413		}
414		for targetRef, want := range desired {
415			targetHash := targetRefs[targetRef]
416			if targetHash.IsZero() {
417				continue
418			}
419			if targetHash == want.SourceHash {
420				continue
421			}
422			return true
423		}
424		return false
425	}
