// CommandStatus is the status of a reference in a report status.
// See ReportStatus struct.
type CommandStatus struct {
	ReferenceName plumbing.ReferenceName
	Status        string
}

// Error returns the error, if any.
func (s *CommandStatus) Error() error {
	if s.Status == ok {
		return nil
	}

	return CommandStatusErr{
		ReferenceName: s.ReferenceName,
		Status:        s.Status,
	}
}

func (s *CommandStatus) encode(w io.Writer) error {
	if s.Error() == nil {
		_, err := pktline.Writef(w, "ok %s\n", s.ReferenceName.String())
		return err
	}

1	// Package materialized implements the materialized fallback push strategy.
2	// This path fetches objects into local memory, then encodes and pushes them
3	// to the target. Used when relay is not safe.
4	package materialized
5	
6	import (
7		"context"
8		"errors"
9		"fmt"
10	
11		git "github.com/go-git/go-git/v6"
12		"github.com/go-git/go-git/v6/plumbing"
13		"github.com/go-git/go-git/v6/plumbing/storer"
14	
15		"entire.io/entire/git-sync/internal/convert"
16		"entire.io/entire/git-sync/internal/gitproto"
17		"entire.io/entire/git-sync/internal/planner"
18	)
19	
20	// Params holds the inputs for a materialized push.
21	type Params struct {
22		Store         storer.Storer
23		SourceConn    *gitproto.Conn
24		SourceService interface {
25			FetchToStore(ctx context.Context, store storer.Storer, conn *gitproto.Conn, desired map[plumbing.ReferenceName]gitproto.DesiredRef, haves map[plumbing.ReferenceName]plumbing.Hash) error
26		}
27		TargetPusher interface {
28			PushObjects(ctx context.Context, cmds []gitproto.PushCommand, store storer.Storer, hashes []plumbing.Hash) error
29		}
30		DesiredRefs map[plumbing.ReferenceName]planner.DesiredRef
31		TargetRefs  map[plumbing.ReferenceName]plumbing.Hash
32		PushPlans   []planner.BranchPlan
33		MaxObjects  int
34	}
35	
36	// DefaultMaxMaterializedObjects is the default safety limit for the materialized fallback path.
37	// Beyond this count, the in-memory object store would consume excessive memory.
38	// Fail early rather than OOM (issue #15).
39	const DefaultMaxMaterializedObjects = 500_000
40	
41	type executor struct {
42		ctx    context.Context
43		params Params
44	}
45	
46	// Execute runs the materialized fallback: ensures tag objects are local,
47	// computes the object closure, and pushes to the target.
48	func Execute(ctx context.Context, p Params) error {
49		if len(p.PushPlans) == 0 {
50			return nil
51		}
52		return (&executor{ctx: ctx, params: p}).run()
53	}
54	
55	func (e *executor) run() error {
56		if err := e.ensureTagObjects(); err != nil {
57			return fmt.Errorf("prepare local objects for push: %w", err)
58		}
59		hashes, err := e.collectObjectClosure()
60		if err != nil {
61			return fmt.Errorf("compute objects to push: %w", err)
62		}
63		if err := e.enforceObjectLimit(hashes); err != nil {
64			return err
65		}
66		return e.push(hashes)
67	}
68	
69	func (e *executor) ensureTagObjects() error {
70		tagDesired := make(map[plumbing.ReferenceName]gitproto.DesiredRef)
71		for _, plan := range e.params.PushPlans {
72			if plan.Kind != planner.RefKindTag {
73				continue
74			}
75			if d, ok := e.params.DesiredRefs[plan.TargetRef]; ok {
76				tagDesired[plan.TargetRef] = gitproto.DesiredRef{
77					SourceRef: d.SourceRef, TargetRef: d.TargetRef,
78					SourceHash: d.SourceHash, IsTag: true,
79				}
80			}
81		}
82		if len(tagDesired) == 0 {
83			return nil
84		}
85		err := e.params.SourceService.FetchToStore(e.ctx, e.params.Store, e.params.SourceConn, tagDesired, nil)
86		if err != nil && !errors.Is(err, git.NoErrAlreadyUpToDate) {
87			return fmt.Errorf("fetch tag objects to store: %w", err)
88		}
89		return nil
90	}
91	
92	func (e *executor) collectObjectClosure() ([]plumbing.Hash, error) {
93		objects := make([]plumbing.Hash, 0, len(e.params.PushPlans))
94		for _, plan := range e.params.PushPlans {
95			if plan.Action == planner.ActionCreate || plan.Action == planner.ActionUpdate {
96				objects = append(objects, plan.SourceHash)
97			}
98		}
99		hashes, err := planner.ObjectsToPush(e.params.Store, objects, e.params.TargetRefs)
100		if err != nil {
101			return nil, fmt.Errorf("compute objects to push: %w", err)
102		}
103		return hashes, nil
104	}
105	
106	func (e *executor) enforceObjectLimit(hashes []plumbing.Hash) error {
107		maxObjects := effectiveMaxObjects(e.params.MaxObjects)
108		if len(hashes) <= maxObjects {
109			return nil
110		}
111		return fmt.Errorf(
112			"materialized push requires %d objects (limit %d); use bootstrap for large initial syncs",
113			len(hashes), maxObjects,
114		)
115	}
116	
117	func (e *executor) push(hashes []plumbing.Hash) error {
118		cmds := convert.PlansToPushCommands(e.params.PushPlans)
119		if e.params.TargetPusher == nil {
120			return errors.New("materialized strategy requires TargetPusher")
121		}
122		if err := e.params.TargetPusher.PushObjects(e.ctx, cmds, e.params.Store, hashes); err != nil {
123			return fmt.Errorf("push target refs: %w", err)
124		}
125		return nil
126	}
127	
128	func effectiveMaxObjects(limit int) int {
129		if limit > 0 {
130			return limit
131		}
132		return DefaultMaxMaterializedObjects
133	}
