// allRefsFlag binds --all-refs to both AllRefs scope and BestEffort policy.
// AllRefs broadens mirroring beyond branches/tags to every refs/* on the
// source; BestEffort downgrades per-ref rejections from receive-pack to
// warnings (e.g. GitHub refs/pull/* hidden refs). Pass nil for bestEffort
// when the subcommand has no policy field (probe, fetch).
func allRefsFlag(cmd *cobra.Command, allRefs, bestEffort *bool) {
	cmd.Flags().BoolVar(allRefs, "all-refs", false,
		"mirror every refs/* on the source (notes, pulls, custom namespaces) on a best-effort basis; "+
			"per-ref server rejections become warnings rather than failing the sync")
	if bestEffort != nil {
		// Bound on the same flag to honor the "best-effort" half of --all-refs.
		// Subcommands that pass nil treat AllRefs as scope-only.
		cobra.OnInitialize(func() {
			if *allRefs {
				*bestEffort = true
			}
		})
	}
}

