313	func captureStdout(fn func() error) (string, error) {
314		old := os.Stdout
315		r, w, err := os.Pipe()
316		if err != nil {
317			return "", err
318		}
319		os.Stdout = w
320		defer func() { os.Stdout = old }()
321	
322		runErr := fn()
323		_ = w.Close()
324	
325		var buf bytes.Buffer
326		if _, err := io.Copy(&buf, r); err != nil {
327			return "", err
328		}
329		_ = r.Close()
330		return strings.TrimSpace(buf.String()), runErr
331	}
