390	type smartHTTPRepoServer struct {
391		t        *testing.T
392		server   *httptest.Server
393		repo     *git.Repository
394		repoPath string
395	
396		mu           sync.Mutex
397		receivePacks int
398		thinCapable  bool
399	}
400	
401	func newSmartHTTPRepoServer(t *testing.T, repo *git.Repository) *smartHTTPRepoServer {
402		t.Helper()
403	
404		s := &smartHTTPRepoServer{
405			t:           t,
406			repo:        repo,
407			repoPath:    "/repo.git",
408			thinCapable: true,
409		}
410		s.server = httptest.NewServer(http.HandlerFunc(s.handle))
411		return s
412	}
413	
414	func (s *smartHTTPRepoServer) Close() {
415		s.server.Close()
416	}
417	
418	func (s *smartHTTPRepoServer) RepoURL() string {
419		return s.server.URL + s.repoPath
420	}
421	
422	func (s *smartHTTPRepoServer) Count(service string) int {
423		s.mu.Lock()
424		defer s.mu.Unlock()
425		if service == "git-receive-pack" {
426			return s.receivePacks
427		}
428		return 0
429	}
430	
431	func (s *smartHTTPRepoServer) handle(w http.ResponseWriter, r *http.Request) {
432		switch {
433		case r.Method == http.MethodGet && r.URL.Path == s.repoPath+"/info/refs":
434			s.handleInfoRefs(w, r)
435		case r.Method == http.MethodPost && r.URL.Path == s.repoPath+"/git-upload-pack":
436			s.handleUploadPack(w, r)
437		case r.Method == http.MethodPost && r.URL.Path == s.repoPath+"/git-receive-pack":
438			s.handleReceivePack(w, r)
439		default:
440			http.NotFound(w, r)
441		}
442	}
443	
444	func (s *smartHTTPRepoServer) handleInfoRefs(w http.ResponseWriter, r *http.Request) {
445		service := r.URL.Query().Get("service")
446		if service != transport.UploadPackService && service != transport.ReceivePackService {
447			http.Error(w, "missing service", http.StatusBadRequest)
448			return
449		}
450	
451		var buf bytes.Buffer
452		if err := transport.AdvertiseRefs(r.Context(), s.repo.Storer, &buf, service, false); err != nil {
453			http.Error(w, err.Error(), http.StatusInternalServerError)
454			return
455		}
456		if service == transport.ReceivePackService && s.thinCapable {
457			rewritten, err := rewriteReceivePackAdvertisement(buf.Bytes(), func(caps *capability.List) {
458				caps.Delete(capability.Capability("no-thin"))
459			})
460			if err != nil {
461				s.t.Fatalf("rewrite receive-pack advertisement: %v", err)
462			}
463			buf.Reset()
464			_, _ = buf.Write(rewritten)
465		}
466	
467		w.Header().Set("Content-Type", fmt.Sprintf("application/x-%s-advertisement", service))
468		if _, err := w.Write(buf.Bytes()); err != nil {
469			s.t.Fatalf("write advertised refs: %v", err)
470		}
471	}
472	
473	func rewriteReceivePackAdvertisement(data []byte, mutate func(*capability.List)) ([]byte, error) {
474		ar := packp.NewAdvRefs()
475		if err := ar.Decode(bytes.NewReader(data)); err == nil {
476			mutate(ar.Capabilities)
477			var buf bytes.Buffer
478			if err := ar.Encode(&buf); err != nil {
479				return nil, err
480			}
481			return buf.Bytes(), nil
482		}
483	
484		rd := bytes.NewReader(data)
485		var smart packp.SmartReply
486		if err := smart.Decode(rd); err != nil {
487			return nil, err
488		}
489		ar = packp.NewAdvRefs()
490		if err := ar.Decode(rd); err != nil {
491			return nil, err
492		}
493		mutate(ar.Capabilities)
494		var buf bytes.Buffer
495		if err := smart.Encode(&buf); err != nil {
496			return nil, err
497		}
498		if err := ar.Encode(&buf); err != nil {
499			return nil, err
500		}
501		return buf.Bytes(), nil
502	}
503	
504	func (s *smartHTTPRepoServer) handleUploadPack(w http.ResponseWriter, r *http.Request) {
505		var buf bytes.Buffer
506		wc := nopWriteCloser{&buf}
507	
508		err := transport.UploadPack(r.Context(), s.repo.Storer, r.Body, wc, &transport.UploadPackRequest{
509			StatelessRPC: true,
510		})
511		if err != nil {
512			http.Error(w, err.Error(), http.StatusInternalServerError)
513			return
514		}
515	
516		w.Header().Set("Content-Type", "application/x-git-upload-pack-result")
517		if _, err := w.Write(buf.Bytes()); err != nil {
518			s.t.Fatalf("write upload-pack response: %v", err)
519		}
520	}
521	
522	func (s *smartHTTPRepoServer) handleReceivePack(w http.ResponseWriter, r *http.Request) {
523		s.mu.Lock()
524		s.receivePacks++
525		s.mu.Unlock()
526	
527		var buf bytes.Buffer
528		wc := nopWriteCloser{&buf}
529	
530		err := transport.ReceivePack(r.Context(), s.repo.Storer, r.Body, wc, &transport.ReceivePackRequest{
531			StatelessRPC: true,
532		})
533	
534		w.Header().Set("Content-Type", "application/x-git-receive-pack-result")
535		if buf.Len() > 0 {
536			if _, err := w.Write(buf.Bytes()); err != nil {
537				s.t.Fatalf("write receive-pack response: %v", err)
538			}
539		}
540		if err != nil {
541			return
542		}
543	}
544	
545	// nopWriteCloser wraps an io.Writer to satisfy io.WriteCloser.
546	type nopWriteCloser struct{ io.Writer }
547	
548	func (nopWriteCloser) Close() error { return nil }
549

1	// Package incremental implements the incremental relay strategy for git-sync.
2	// This fast-path streams a pack from source directly to target when all updates
3	// are fast-forward branch updates or new tag creates.
4	package incremental
5	
6	import (
7		"context"
8		"errors"
9		"fmt"
10		"io"
11		"sync"
12	
13		"github.com/go-git/go-git/v6/plumbing"
14	
15		"entire.io/entire/git-sync/internal/convert"
16		"entire.io/entire/git-sync/internal/gitproto"
17		"entire.io/entire/git-sync/internal/planner"
18	)
19	
20	// Params holds the inputs for an incremental relay execution.
21	type Params struct {
22		SourceConn    *gitproto.Conn
23		SourceService interface {
24			FetchPack(ctx context.Context, conn *gitproto.Conn, desired map[plumbing.ReferenceName]gitproto.DesiredRef, haves map[plumbing.ReferenceName]plumbing.Hash) (io.ReadCloser, error)
25		}
26		TargetPusher interface {
27			PushPack(ctx context.Context, cmds []gitproto.PushCommand, pack io.ReadCloser) error
28		}
29		DesiredRefs  map[plumbing.ReferenceName]planner.DesiredRef
30		TargetRefs   map[plumbing.ReferenceName]plumbing.Hash
31		PushPlans    []planner.BranchPlan
32		MaxPackBytes int64
33		Verbose      bool
34		CanRelay     func(bool, bool, bool, []planner.BranchPlan) (bool, string)
35		CanTagRelay  func([]planner.BranchPlan) (bool, string)
36	}
37	
38	// Result holds the outcome of an incremental relay.
39	type Result struct {
40		Relay       bool
41		RelayMode   string
42		RelayReason string
43	}
44	
45	// Execute attempts the incremental relay strategy. Returns (result, nil) on
46	// success, or (zero, nil) if the strategy is not applicable. Errors indicate
47	// a relay was attempted but failed.
48	func Execute(ctx context.Context, p Params, cfg planner.PlanConfig) (Result, error) {
49		canRelay := p.CanRelay
50		if canRelay == nil {
51			return Result{}, errors.New("incremental strategy requires CanRelay")
52		}
53		if p.TargetPusher == nil {
54			return Result{}, errors.New("incremental strategy requires TargetPusher")
55		}
56		cmds := convert.PlansToPushCommands(p.PushPlans)
57		if ok, reason := canRelay(cfg.Force, cfg.Prune, false, p.PushPlans); ok {
58			desired := convert.DesiredRefsForPlans(p.DesiredRefs, p.PushPlans)
59			packReader, err := p.SourceService.FetchPack(ctx, p.SourceConn, desired, p.TargetRefs)
60			if err != nil {
61				return Result{}, fmt.Errorf("fetch source pack: %w", err)
62			}
63			packReader = gitproto.LimitPackReader(packReader, p.MaxPackBytes)
64			packReader = closeOnce(packReader)
65			if err := p.TargetPusher.PushPack(ctx, cmds, packReader); err != nil {
66				_ = packReader.Close()
67				return Result{}, fmt.Errorf("push target refs: %w", err)
68			}
69			_ = packReader.Close()
70			return Result{Relay: true, RelayMode: "incremental", RelayReason: reason}, nil
71		}
72	
73		if p.CanTagRelay == nil {
74			return Result{}, errors.New("incremental strategy requires CanTagRelay")
75		}
76		if ok, reason := p.CanTagRelay(p.PushPlans); ok {
77			desired := convert.DesiredRefsForPlans(p.DesiredRefs, p.PushPlans)
78			packReader, err := p.SourceService.FetchPack(ctx, p.SourceConn, desired, nil)
79			if err != nil {
80				return Result{}, fmt.Errorf("fetch source tag pack: %w", err)
81			}
82			packReader = gitproto.LimitPackReader(packReader, p.MaxPackBytes)
83			packReader = closeOnce(packReader)
84			if err := p.TargetPusher.PushPack(ctx, cmds, packReader); err != nil {
85				_ = packReader.Close()
86				return Result{}, fmt.Errorf("push target refs: %w", err)
87			}
88			_ = packReader.Close()
89			return Result{Relay: true, RelayMode: "incremental", RelayReason: reason}, nil
90		}
91	
92		return Result{}, nil
93	}
94	
95	type closeOnceReadCloser struct {
96		io.ReadCloser
97	
98		once sync.Once
99	}
100	
101	func (c *closeOnceReadCloser) Close() error {
102		var err error
103		c.once.Do(func() {
104			err = c.ReadCloser.Close()
105		})
106		if err != nil {
107			return fmt.Errorf("close pack reader: %w", err)
108		}
109		return nil
110	}
111	
112	func closeOnce(rc io.ReadCloser) io.ReadCloser {
113		if rc == nil {
114			return nil
115		}
116		if _, ok := rc.(*closeOnceReadCloser); ok {
117			return rc
118		}
119		return &closeOnceReadCloser{ReadCloser: rc}
120	}
