// pointer in implies is set to true when --all-refs is set, via a PreRunE
// hook that fires after flag parsing.
func allRefsFlag(cmd *cobra.Command, allRefs *bool, implies ...*bool) {
	cmd.Flags().BoolVar(allRefs, "all-refs", false,
		"mirror every refs/* on the source (branches, tags, notes, pulls, custom namespaces) on a best-effort basis; "+
			"per-ref server rejections become warnings rather than failing the sync")
	if len(implies) == 0 {
		return
	}
	prev := cmd.PreRunE
	cmd.PreRunE = func(cmd *cobra.Command, args []string) error {
		if *allRefs {
			for _, p := range implies {
				if p != nil {
					*p = true
				}
			}
		}
		if prev != nil {
			return prev(cmd, args)
		}
		return nil
	}
}

